import{c as n,Q as s,j as e,m as t}from"./chunks/framework.CBiVa4O3.js";const h=JSON.parse('{"title":"Gin 框架实战(二)：项目目录分层设计","description":"","frontmatter":{},"headers":[],"relativePath":"../goLearning/25-Gin框架实战(二)：项目目录分层设计.md","filePath":"../goLearning/25-Gin框架实战(二)：项目目录分层设计.md","lastUpdated":1778496697000}'),p={name:"../goLearning/25-Gin框架实战(二)：项目目录分层设计.md"};function o(i,a,l,r,c,d){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="gin-框架实战-二-项目目录分层设计" tabindex="-1">Gin 框架实战(二)：项目目录分层设计 <a class="header-anchor" href="#gin-框架实战-二-项目目录分层设计" aria-label="Permalink to &quot;Gin 框架实战(二)：项目目录分层设计&quot;">​</a></h1><blockquote><p><strong>导读</strong>：Go 语言本身没有规定项目必须怎么分层（不像 Java Spring Boot）。良好的目录结构（Clean Architecture）是防止代码腐化的关键。</p></blockquote><h2 id="一、标准-go-语言工程结构-standard-go-project-layout" tabindex="-1">一、标准 Go 语言工程结构 (Standard Go Project Layout) <a class="header-anchor" href="#一、标准-go-语言工程结构-standard-go-project-layout" aria-label="Permalink to &quot;一、标准 Go 语言工程结构 (Standard Go Project Layout)&quot;">​</a></h2><p>业界公认的一套项目目录组织规范：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>├── cmd/           # 程序的入口，每个子目录对应一个可执行文件（如 cmd/api/main.go）</span></span>
<span class="line"><span>├── internal/      # 核心私有业务逻辑。Go 编译器会强制限制 internal 外的包无法 import 这里的代码！</span></span>
<span class="line"><span>├── pkg/           # 可以被外部其他项目 import 的公用工具库（如果不打算开源复用，尽量少用 pkg）</span></span>
<span class="line"><span>├── api/           # OpenAPI/Swagger 接口定义文件、Protocol Buffers 契约文件</span></span>
<span class="line"><span>├── configs/       # 配置文件模板 (yaml, json)</span></span>
<span class="line"><span>├── scripts/       # 构建、部署用的 Bash/Makefile 脚本</span></span>
<span class="line"><span>└── go.mod         # 依赖管理</span></span></code></pre></div><h2 id="二、internal-内部的三层架构模型" tabindex="-1">二、Internal 内部的三层架构模型 <a class="header-anchor" href="#二、internal-内部的三层架构模型" aria-label="Permalink to &quot;二、Internal 内部的三层架构模型&quot;">​</a></h2><p>在 <code>internal/</code> 目录下，最经典的做法是按照 Controller-Service-Repository 三层拆分。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>internal/</span></span>
<span class="line"><span> ├── handler/  (或 controller)</span></span>
<span class="line"><span> │     # 负责接收 HTTP 请求(gin.Context)，参数绑定与校验，返回 JSON 响应。不包含核心业务。</span></span>
<span class="line"><span> │</span></span>
<span class="line"><span> ├── service/  (或 logic/usecase)</span></span>
<span class="line"><span> │     # 核心业务逻辑层。接收纯数据结构，处理核心规则，调用 repo。完全不依赖 Gin。</span></span>
<span class="line"><span> │</span></span>
<span class="line"><span> └── repo/     (或 dao)</span></span>
<span class="line"><span>       # 数据访问层。封装所有数据库 CRUD 和 Redis 缓存操作。对外只暴露接口。</span></span></code></pre></div><h2 id="三、为什么非要拆分" tabindex="-1">三、为什么非要拆分？ <a class="header-anchor" href="#三、为什么非要拆分" aria-label="Permalink to &quot;三、为什么非要拆分？&quot;">​</a></h2><p>有些新手喜欢在 Handler 里一把梭（直接把 <code>db.Where(...)</code> 写在 Gin 路由里）。 一旦业务变得复杂，或者需要写单元测试时：</p><ul><li><strong>解耦隔离</strong>：Service 层不需要知道外层是 HTTP 还是 gRPC 请求，这使得业务逻辑极其容易复用。</li><li><strong>方便 Mock</strong>：因为 Repo 是接口，在测试 Service 时，你可以传入一个 MockRepo（不在真实 DB 写入数据），实现飞快且隔离的单元测试。</li><li><strong>依赖倒置</strong>：这是大型项目必备的架构心智模型。配合 Google 的 <code>Wire</code> 依赖注入库体验极佳。</li></ul>`,11)])])}const _=n(p,[["render",o]]);export{h as __pageData,_ as default};
